    ws,
    messages,
    send(payload) {
      ws.send(JSON.stringify(payload));
    },
    latestState() {
      for (let i = messages.length - 1; i >= 0; i -= 1) {
        if (messages[i].type === 'state') return messages[i];
      }
      return null;
    },
  };
}

