const sampleRate = 44100;
const durationSec = 14;
const channels = 1;
const bitsPerSample = 16;
const totalSamples = sampleRate * durationSec;
const dataSize = totalSamples * channels * (bitsPerSample / 8);
const buffer = Buffer.alloc(44 + dataSize);

function writeString(offset, str) {
  buffer.write(str, offset, str.length, 'ascii');
}

writeString(0, 'RIFF');
buffer.writeUInt32LE(36 + dataSize, 4);
writeString(8, 'WAVE');
writeString(12, 'fmt ');
buffer.writeUInt32LE(16, 16); // PCM chunk size
buffer.writeUInt16LE(1, 20); // format PCM
buffer.writeUInt16LE(channels, 22);
buffer.writeUInt32LE(sampleRate, 24);
const byteRate = sampleRate * channels * (bitsPerSample / 8);
buffer.writeUInt32LE(byteRate, 28);
const blockAlign = channels * (bitsPerSample / 8);
buffer.writeUInt16LE(blockAlign, 32);
buffer.writeUInt16LE(bitsPerSample, 34);
writeString(36, 'data');
buffer.writeUInt32LE(dataSize, 40);

for (let i = 0; i < totalSamples; i += 1) {
  const t = i / sampleRate;
  const fadeIn = Math.min(1, t / 2.0);
  const fadeOut = Math.min(1, (durationSec - t) / 2.0);
  const env = Math.max(0, Math.min(fadeIn, fadeOut));
  const bed = Math.sin(2 * Math.PI * 110 * t) * 0.28;
  const layer = Math.sin(2 * Math.PI * 165 * t) * 0.18;
  const shimmer = Math.sin(2 * Math.PI * (220 + Math.sin(2 * Math.PI * 0.07 * t) * 8) * t) * 0.08;
  const pulse = Math.sin(2 * Math.PI * 0.3 * t) * 0.05;
  const sample = (bed + layer + shimmer + pulse) * env;
  const clamped = Math.max(-1, Math.min(1, sample));
  buffer.writeInt16LE(Math.round(clamped * 32767), 44 + i * 2);
}

